// // This is a synchronous reset Johnson counter that cycles through states: 11, 10, 00, 01
module johnson_counter (
  input clk,
  input reset,
  output reg [1:0] state
);always @(posedge clk or posedge reset) begin
    if (reset)
        state <= 2'b00;
    else
        state <= {state[0], ~state[1]};
end

endmodule
